#!/usr/bin/perl
use strict;
use warnings;
use CGI;

my $query = CGI->new;
print $query->header('text/plain');

my $log_dir = '/path/to/log/files';
my $filename = $query->param('logfile');

if ($filename && $filename =~ /^[a-zA-Z0-9._-]+$/) {
    my $filepath = "$log_dir/$filename";
    if (open(my $fh, '<', $filepath)) {
        while (my $line = <$fh>) {
            print $line;
        }
        close($fh);
    } else {
        print "Error: Unable to open file $filepath\n";
    }
} else {
    print "Error: Invalid or missing logfile parameter\n";
}